func toolDefinitions() []map[string]any {
	ragSpecs := tasks.RAGAliasSpecs()
	defs := make([]map[string]any, 0, len(ragSpecs)+12)
	for _, spec := range ragSpecs {
		properties := map[string]any{
			"input_refs":           inputRefsSchema(),
			"retrieval_strategies": retrievalStrategiesSchema(),
			"task_params":          map[string]any{"type": "object"},
			"constraints":          ragConstraintsSchema(),
			"execution_profile":    ragExecutionProfileSchema(),
			"idempotency_key":      map[string]any{"type": "string"},
			"wait_for_result":      map[string]any{"type": "boolean"},
			"max_wait_seconds":     map[string]any{"type": "integer"},
			"poll_interval_ms":     map[string]any{"type": "integer"},
		}
		if spec.PromptField != "" {
			properties[spec.PromptField] = map[string]any{"type": "string"}
		}
		if spec.Name == "inspect_repo" {
			properties["query"] = map[string]any{"type": "string", "maxLength": tasks.MaxInspectRepoQueryBytes}
			properties["constraints"] = inspectRepoConstraintsSchema()
			properties["mode"] = map[string]any{
				"type":    "string",
				"enum":    []string{"auto", "evidence", "answer"},
				"default": "auto",
			}
			properties["include_full_trace"] = map[string]any{"type": "boolean", "default": false}
		}
		defs = append(defs, ragToolDefinition(spec.Name, spec.Description, spec.Required, properties))
	}
	for _, spec := range coreToolDefinitions() {
		defs = append(defs, map[string]any{
			"name":        spec.name,
			"description": spec.description,
			"inputSchema": spec.inputSchema,
		})
	}
	return defs
}

func (s *Service) stageExecutionBundle(ctx context.Context, job *types.Job) error {
	jobDir := filepath.Join(s.runRoot, job.ID)
	if err := os.MkdirAll(jobDir, 0o700); err != nil {
		return err
	}
	if err := os.Chmod(jobDir, 0o700); err != nil {
		return err
	}

	jobSpecPath := filepath.Join(jobDir, "job_spec.json")
	executionPlanPath := filepath.Join(jobDir, "execution_plan.json")
	inputManifestPath := filepath.Join(jobDir, "input_manifest.json")

	if err := writeJSONFile(jobSpecPath, map[string]any{
		"job_id":        job.ID,
		"task_type":     job.TaskType,
		"task_params":   s.executionTaskParams(*job),
		"output_schema": job.Request.OutputSchema,
		"constraints":   job.Request.Constraints,
	}); err != nil {
		return err
	}
	executionPlan := map[string]any{
		"job_id":             job.ID,
		"task_type":          job.TaskType,
		"execution_profile":  job.Request.ExecutionProfile,
		"selected_model":     job.Request.ExecutionProfile.Model,
		"runtime_backend":    job.Request.ExecutionProfile.Runtime,
		"resource_tier":      job.Request.ExecutionProfile.Tier,
		"runtime_connection": s.runtimeConnectionPlan(job.Request.ExecutionProfile),
	}
	if job.TaskType == "inspect_repo" && s.gpuServices.Enabled {
		executionPlan["gpu_service_registry_path"] = s.gpuServices.RegistryPath
		executionPlan["gpu_service_request_path"] = s.gpuServices.ControlRequestPath
		executionPlan["gpu_service_health_interval_seconds"] = s.gpuServices.HealthIntervalSeconds
		executionPlan["gpu_service_startup_timeout_seconds"] = s.gpuServices.StartupTimeoutSeconds
		executionPlan["gpu_service_control_token"] = s.gpuServices.ControlToken
	}
	if job.TaskType == "inspect_repo" {
		executionPlan["repo_inspection_cache_path"] = filepath.Join(s.runRoot, "repo-inspection-cache")
	}
	if err := writeJSONFile(executionPlanPath, executionPlan); err != nil {
		return err
	}

	resolvedInputRefs := append([]types.InputRef(nil), job.Request.InputRefs...)
	if !inputRefsReadyForExecution(resolvedInputRefs) {
		var err error
		resolvedInputRefs, err = s.resolveInputRefs(ctx, *job)
		if err != nil {
			return err
		}
	}

	if err := writeJSONFile(inputManifestPath, map[string]any{
		"job_id":     job.ID,
		"input_refs": resolvedInputRefs,
	}); err != nil {
		return err
	}
	job.Request.InputRefs = resolvedInputRefs

	return nil
}

func validateRepoInspectionV2(taskType string, payload map[string]any) error {
	if taskType != "inspect_repo" {
		return fmt.Errorf("schema repo_inspection_v2 is incompatible with task type %q", taskType)
	}
	query, ok := payload["query"].(string)
	if !ok || strings.TrimSpace(query) == "" {
		return fmt.Errorf("payload.query must be a non-empty string")
	}
	mode, ok := payload["mode"].(string)
	if !ok {
		return fmt.Errorf("payload.mode must be a string")
	}
	mode = strings.ToLower(strings.TrimSpace(mode))
	switch mode {
	case "auto", "evidence", "answer":
	default:
		return fmt.Errorf("payload.mode must be one of auto, evidence, or answer")
	}

	evidence, ok := payload["evidence"].([]any)
	if !ok {
		return fmt.Errorf("payload.evidence must be an array")
	}
	if len(evidence) > 12 {
		return fmt.Errorf("payload.evidence cannot contain more than 12 chunks")
	}
	evidenceIDs := make(map[string]struct{}, len(evidence))
	for index, raw := range evidence {
		item, ok := raw.(map[string]any)
		if !ok {
			return fmt.Errorf("payload.evidence[%d] must be an object", index)
		}
		id, ok := item["id"].(string)
		id = strings.TrimSpace(id)
		if !ok || id == "" {
			return fmt.Errorf("payload.evidence[%d].id must be a non-empty string", index)
		}
		if _, exists := evidenceIDs[id]; exists {
			return fmt.Errorf("payload.evidence[%d].id %q is duplicated", index, id)
		}
		evidenceIDs[id] = struct{}{}
		sourceRefs, ok := item["source_refs"].([]any)
		if !ok || len(sourceRefs) == 0 {
			return fmt.Errorf("payload.evidence[%d].source_refs must be a non-empty array", index)
		}
		for refIndex, rawRef := range sourceRefs {
			ref, ok := rawRef.(map[string]any)
			if !ok || strings.TrimSpace(stringField(ref, "path")) == "" {
				return fmt.Errorf("payload.evidence[%d].source_refs[%d].path must be a non-empty string", index, refIndex)
			}
		}
	}

	findings, ok := payload["findings"].([]any)
	if !ok {
		return fmt.Errorf("payload.findings must be an array")
	}
	for index, raw := range findings {
		finding, ok := raw.(map[string]any)
		if !ok {
			return fmt.Errorf("payload.findings[%d] must be an object", index)
		}
		if strings.TrimSpace(stringField(finding, "summary")) == "" {
			return fmt.Errorf("payload.findings[%d].summary must be a non-empty string", index)
		}
		refs, ok := finding["evidence_refs"].([]any)
		if !ok || len(refs) == 0 {
			return fmt.Errorf("payload.findings[%d].evidence_refs must be a non-empty array", index)
		}
		for _, rawRef := range refs {
			ref, ok := rawRef.(string)
			if !ok || strings.TrimSpace(ref) == "" {
				return fmt.Errorf("payload.findings[%d].evidence_refs must contain strings", index)
			}
			if _, exists := evidenceIDs[strings.TrimSpace(ref)]; !exists {
				return fmt.Errorf("payload.findings[%d] references unknown evidence %q", index, ref)
			}
		}
	}

	quality, ok := payload["quality"].(map[string]any)
	if !ok {
		return fmt.Errorf("payload.quality must be an object")
	}
	resultState := strings.TrimSpace(stringField(quality, "result"))
	retrievalState := strings.TrimSpace(stringField(quality, "retrieval"))
	rerankingState := strings.TrimSpace(stringField(quality, "reranking"))
	synthesisState := strings.TrimSpace(stringField(quality, "synthesis"))
	answerReady, ok := quality["answer_ready"].(bool)
	if !ok {
		return fmt.Errorf("payload.quality.answer_ready must be a boolean")
	}
	if !oneOf(retrievalState, "gpu", "lexical_degraded", "failed") {
		return fmt.Errorf("payload.quality.retrieval has an invalid state")
	}
	if !oneOf(rerankingState, "gpu", "unavailable", "failed") {
		return fmt.Errorf("payload.quality.reranking has an invalid state")
	}
	if !oneOf(synthesisState, "gpu", "not_requested", "failed") {
		return fmt.Errorf("payload.quality.synthesis has an invalid state")
	}
	retrievalDiagnostics, ok := payload["retrieval"].(map[string]any)
	if !ok {
		return fmt.Errorf("payload.retrieval must be an object")
	}
	_ = retrievalDiagnostics
	runtime, ok := payload["runtime"].(map[string]any)
	if !ok {
		return fmt.Errorf("payload.runtime must be an object")
	}
	rawAttempts, ok := runtime["attempts"].([]any)
	if !ok {
		return fmt.Errorf("payload.runtime.attempts must be an array")
	}
	attempts, err := validateGPUAttempts(rawAttempts)
	if err != nil {
		return err
	}

def ensure_semantic_index(self, chunks, fingerprint, *, batch_size=32, sync_plan=None, content_loader=None):
    """Ensure the retrieval service owns a finalized fingerprinted index.

    Warm queries send only the fingerprint and document count. Repository
    content is uploaded in bounded batches only when the service reports a
    cache miss; the service is responsible for embeddings and persistent
    FAISS construction.
    """

    status_body = {
        "model": self.model,
        "model_profile": self.model_profile,
        "index_fingerprint": fingerprint,
        "document_count": len(chunks),
    }
    status = self._post("index_status", "v1/indexes/status", status_body)
    if status.get("ready") is True:
        return {
            "cache_hit": True,
            "document_count": int(status.get("document_count") or len(chunks)),
            "embedded_documents": 0,
            "reused_documents": 0,
        }
    if not chunks:
        raise GPUServiceError("service_failure", "semantic index has no repository chunks")
    if batch_size < 1:
        raise GPUServiceError("service_failure", "semantic index batch size must be positive")

    def upload(selected_chunks, *, base_fingerprint="", removed_ids=None):
        removed_ids = list(removed_ids or [])
        if selected_chunks and any("content" not in chunk for chunk in selected_chunks):
            if content_loader is None:
                raise GPUServiceError("service_failure", "semantic index requires chunk content")
            content_loader(selected_chunks)
            if any("content" not in chunk for chunk in selected_chunks):
                raise GPUServiceError("service_failure", "semantic index content loader did not hydrate chunk content")
        batches = []
        batch = []
        batch_bytes = 0
        for chunk in selected_chunks:
            document = self._index_document(chunk)
            document_bytes = len(json.dumps(document, separators=(",", ":"), ensure_ascii=True).encode("utf-8"))
            if document_bytes > MAX_INDEX_BATCH_BYTES:
                raise GPUServiceError("service_failure", "one semantic index document exceeds the upload limit")
            if batch and (len(batch) >= batch_size or batch_bytes + document_bytes > MAX_INDEX_BATCH_BYTES):
                batches.append(batch)
                batch = []
                batch_bytes = 0
            batch.append(document)
            batch_bytes += document_bytes
        if batch or removed_ids or base_fingerprint:
            batches.append(batch)

        embedded_documents = 0
        reused_documents = 0
        first_response = {}
        for batch_index, documents in enumerate(batches):
            final = batch_index == len(batches) - 1
            body = {
                "model": self.model,
                "model_profile": self.model_profile,
                "index_fingerprint": fingerprint,
                "document_count": len(chunks),
                "replace": batch_index == 0,
                "finalize": final,
                "documents": documents,
            }
            if batch_index == 0 and base_fingerprint:
                body["base_index_fingerprint"] = base_fingerprint
            if batch_index == 0 and removed_ids:
                body["removed_document_ids"] = removed_ids
            response = self._post("index_upsert", "v1/indexes/upsert", body)
            if batch_index == 0:
                first_response = response
            if response.get("accepted") is False:
                raise GPUServiceError("service_failure", "semantic index rejected an update batch")
            embedded_documents += int(response.get("embedded_documents") or 0)
            reused_documents += int(response.get("reused_documents") or 0)
        return embedded_documents, reused_documents, first_response

    embedded_documents = 0
    reused_documents = 0
    base_fingerprint = str((sync_plan or {}).get("base_fingerprint") or "")
    changed_ids = {str(value) for value in ((sync_plan or {}).get("changed_ids") or []) if str(value)}
    removed_ids = [str(value) for value in ((sync_plan or {}).get("removed_ids") or []) if str(value)]
    if base_fingerprint:
        changed_chunks = self._select_changed_chunks(chunks, changed_ids)
        embedded_documents, reused_documents, first_response = upload(
            changed_chunks,
            base_fingerprint=base_fingerprint,
            removed_ids=removed_ids,
        )
        if first_response.get("base_reused") is not True:
            embedded_documents, reused_documents, _ = upload(chunks)
    else:
        embedded_documents, reused_documents, _ = upload(chunks)

    status = self._post("index_status", "v1/indexes/status", status_body)
    if status.get("ready") is not True:
        raise GPUServiceError("service_failure", "semantic index did not finalize the requested fingerprint")
    return {
        "cache_hit": False,
        "document_count": int(status.get("document_count") or len(chunks)),
        "embedded_documents": embedded_documents,
        "reused_documents": reused_documents,
    }

func maybeAttachInspectRepoFingerprintHint(req *types.SubmitJobRequest, contentHash string) {
	if req == nil || req.TaskType != "inspect_repo" {
		return
	}
	contentHash = strings.TrimSpace(contentHash)
	if contentHash == "" || len(req.InputRefs) != 1 {
		return
	}
	inputType := strings.ToLower(strings.TrimSpace(req.InputRefs[0].Type))
	if inputType != "repo" && inputType != "directory" {
		return
	}
	if hasInspectRepoCustomExclusions(req.TaskParams) {
		return
	}
	taskParams := cloneTaskParams(req.TaskParams)
	taskParams["_broker_repository_state_fingerprint"] = contentHash
	taskParams["_broker_repository_state_fingerprint_source"] = "request_cache"
	req.TaskParams = taskParams
}

def _artifact_payloads(payload, fingerprint, cache_dir, full_trace=False):
    artifacts = {
        "evidence_pack": {"query": payload["query"], "evidence": payload["evidence"]},
        "retrieval_result": {
            "fingerprint": fingerprint,
            "lexical_index": str(Path(cache_dir) / "lexical-working.sqlite3"),
            "lexical_index_cache_hit": False,
            **(payload.get("retrieval") or {}),
            "selected": [
                {
                    "id": item["id"],
                    "path": item["path"],
                    "source_refs": item["source_refs"],
                }
                for item in payload["evidence"]
            ],
        },
        "runtime_diagnostics": payload.get("runtime") or {},
    }
    if full_trace:
        artifacts["chunk_manifest"] = {
            "fingerprint": fingerprint,
            "chunks": [],
            "selected_chunk_ids": [],
        }
    return artifacts
